        ('chemistry', 'Reaction Rate',
         '{"description":"The speed at which a chemical reaction proceeds over time","category":"Kinetics & Equilibrium","difficulty":2,"popularity":85,"group":"Kinetics & Equilibrium","primary_val":"rate = Δ[concentration]/Δt","secondary_val":"mol/(L*s)","definition":"Reaction rate measures the change in concentration of reactants or products per unit time.","unit":"mol/(L*s)","images":[]}',
